actions.script:
boolean wasDisabled = ec.artifactExecution.disableAuthz()
try {
    def inst = ec.entity.find("trade.TradeInstrument").condition("instrumentId", instrumentId).one()
    if (inst != null) {
        def newPrio = priorityEnumId ?: inst.priorityEnumId
        inst.priorityEnumId = newPrio
        if (!inst.makerUserId) inst.makerUserId = makerUserId
        inst.update()
    }
} finally {
    if (!wasDisabled) ec.artifactExecution.enableAuthz()
}
